# main.tf — root module calling all ALZ child modules
# Uses the caf-enterprise-scale Terraform module from the Terraform Registry.
# This module encapsulates the full ALZ pattern with input variables.

terraform {
  required_version = ">= 1.7"
  required_providers {
    azurerm = { source = "hashicorp/azurerm", version = "~> 3.100" }
  }
  backend "azurerm" {
    resource_group_name  = "rg-tfstate-mgmt-eastus"
    storage_account_name = "stgtfstatecore"
    container_name       = "tfstate"
    key                  = "alz.tfstate"
  }
}

provider "azurerm" {
  features {}
}

provider "azurerm" {
  alias           = "connectivity"
  features {}
  subscription_id = var.connectivity_sub_id
}

# The official Terraform ALZ module from the registry
module "alz" {
  source  = "Azure/caf-enterprise-scale/azurerm"
  version = "~> 5.2"

  # Required: tenant root MG parent for the ALZ hierarchy
  root_parent_id = data.azurerm_client_config.current.tenant_id

  # Root management group settings
  root_id          = var.top_level_mg_prefix
  root_name        = "Azure Landing Zones"

  # Deploy policy definitions and assignments
  deploy_core_landing_zones   = true
  deploy_management_resources = true
  deploy_connectivity_resources = true
  deploy_identity_resources   = true

  # Management baseline configuration
  configure_management_resources = {
    settings = {
      log_analytics = {
        enabled = true
        config  = {
          retention_in_days             = 90
          enable_sentinel               = true
          enable_change_tracking        = true
          enable_solution_for_vm_insights = true
        }
      }
    }
    location = var.location
    tags     = var.tags
  }

  # Connectivity (hub-spoke)
  configure_connectivity_resources = {
    settings = {
      hub_networks = [
        {
          enabled = true
          config = {
            address_space                = ["10.0.0.0/16"]
            location                     = var.location
            enable_hub_network_mesh_peering = false
            enable_private_dns_zones     = true
            private_dns_zones_to_exclude = []
            azure_firewall = {
              enabled          = true
              availability_zones = { zone_1 = true, zone_2 = true, zone_3 = true }
              sku_tier         = "Premium"
              enable_dns_proxy = true
            }
            expressroute_gateway = {
              enabled = true
              config  = { gateway_sku_expressroute = "ErGw2AZ" }
            }
          }
        }
      ]
    }
    location       = var.location
    tags           = var.tags
    subscription_id = var.connectivity_sub_id
  }
}

data "azurerm_client_config" "current" {}

# prod.tfvars — production environment variable values
# Run with: terraform plan -var-file=prod.tfvars

top_level_mg_prefix = "alz"
location            = "eastus"
connectivity_sub_id = "<connectivity-sub-id>"

tags = {
  Environment = "Production"
  ManagedBy   = "Terraform"
  CostCenter  = "platform"
}

# dev.tfvars — development / test environment
# top_level_mg_prefix = "alz-dev"
# location            = "eastus2"
# connectivity_sub_id = "<connectivity-dev-sub-id>"

# variables.tf — variable declarations (checked into git, no default values for secrets)
# variable "top_level_mg_prefix" { type = string }
# variable "location"            { type = string }
# variable "connectivity_sub_id" { type = string }
# variable "tags"                { type = map(string) }
